function washDishesManually(dirtyDishes) {
    // 1. Подготовка раковины и моющего раствора
    sink = getSink()
    fill(sink, water: HOT, soap: DISH_SOAP)
    generateSuds(sink)
    sponge = getSponge()
    dryingRack = getDryingRack()

    // 2. Предварительное замачивание сильно загрязнённых предметов
    for each dish in dirtyDishes {
        if dish.soilLevel >= HEAVY {
            soak(dish, sink, duration: MINUTES(3))
        }
    }

    // 3. Основной цикл: мытьё → ополаскивание → размещение на сушилке
    cleanDishes = []
    for each dish in dirtyDishes {
        scrub(dish, sponge, targetAreas: [corners, crevices, surfaces])
        rinse(dish, water: HOT, useSprayNozzle: true)
        placeOnRack(dish, dryingRack)
