#pragma once
#include <vector>
#include <string>
#include <cstdint>
#include <cuda_runtime.h>

struct QueryResult {
    std::vector<int> indices;
    std::vector<float> distances;
    double query_time_ms = 0.0;
};

class KNNWrapper {
public:
    explicit KNNWrapper(int device_id = 0);
    ~KNNWrapper();

    // Загрузка данных (бинарный формат: [N][D][float32])
    void loadDataset(const std::string& path, int dim, int num_points);

    // Построение графа KNN (точный или приближённый)
    void buildGraph(int k, float metric = 0.0f); // 0.0=L2, 1.0=IP

    // Уточнение графа (взаимный KNN, пороговая обрезка)
    void refineGraph(int k_refine, float threshold = 0.0f);

    // Генерация эталонных данных (ground truth)
    void generateReferenceData(int k_ref, const std::string& out_path);

    // Оценка качества графа
    void evaluateGraph(const std::string& ref_path, float& recall, double& latency_ms);

    // Выполнение запросов
    QueryResult query(const float* queries, int num_queries, int k, bool verbose = false);

    // Сохранение/загрузка графа
    void saveGraph(const std::string& path) const;
    void loadGraph(const std::string& path);

    // Сброс графа до подмножества
    void resetSubset(int new_size);

    // Настройки отладки
    void setDebug(bool debug) { debug_ = debug; }
    void setVerbose(bool verbose) { verbose_ = verbose; }

private:
    // GPU-указатели
    float* d_data_ = nullptr;
    int* d_graph_indices_ = nullptr;
    float* d_graph_distances_ = nullptr;

    // Состояние
    int num_points_ = 0;
    int dim_ = 0;
    int k_ = 0;
    int device_id_ = 0;
    bool debug_ = false;
    bool verbose_ = false;

    // Внутренние методы
    void allocateDeviceMemory();
    void freeDeviceMemory();
    void computeDistancesGPU(const float* d_queries, int num_queries, int* d_indices, float* d_distances);
    void topKSelectionGPU(const float* d_distances, int num_queries, int k, int* d_indices, float* d_values);
    void mutualKNNRefineGPU(int k_refine, float threshold);
    void log(const std::string& msg) const;
};
