#include "knn_wrapper.h"
#include <thrust/device_ptr.h>
#include <thrust/sort.h>
#include <thrust/sequence.h>
#include <thrust/execution_policy.h>
#include <fstream>
#include <iostream>
#include <chrono>
#include <numeric>
