#define CUDA_CHECK(call) \
    do { \
        cudaError_t err = call; \
        if (err != cudaSuccess) { \
            std::cerr << "CUDA Error: " << cudaGetErrorString(err) \
                      << " at " << __FILE__ << ":" << __LINE__ << std::endl; \
            exit(EXIT_FAILURE); \
        } \
    } while (0)

KNNWrapper::KNNWrapper(int device_id) : device_id_(device_id) {
    CUDA_CHECK(cudaSetDevice(device_id_));
    log("KNNWrapper initialized on device " + std::to_string(device_id_));
}

KNNWrapper::~KNNWrapper() {
    freeDeviceMemory();
}

void KNNWrapper::log(const std::string& msg) const {
    if (debug_ || verbose_) {
        std::cout << "[KNNWrapper] " << msg << std::endl;
    }
}

void KNNWrapper::allocateDeviceMemory() {
    freeDeviceMemory();
    if (num_points_ > 0 && dim_ > 0) {
        CUDA_CHECK(cudaMalloc(&d_data_, num_points_ * dim_ * sizeof(float)));
    }
    if (k_ > 0 && num_points_ > 0) {
        CUDA_CHECK(cudaMalloc(&d_graph_indices_, num_points_ * k_ * sizeof(int)));
        CUDA_CHECK(cudaMalloc(&d_graph_distances_, num_points_ * k_ * sizeof(float)));
    }
}

void KNNWrapper::freeDeviceMemory() {
    if (d_data_) { cudaFree(d_data_); d_data_ = nullptr; }
    if (d_graph_indices_) { cudaFree(d_graph_indices_); d_graph_indices_ = nullptr; }
    if (d_graph_distances_) { cudaFree(d_graph_distances_); d_graph_distances_ = nullptr; }
}

void KNNWrapper::loadDataset(const std::string& path, int dim, int num_points) {
    dim_ = dim;
    num_points_ = num_points;
    allocateDeviceMemory();

    std::ifstream file(path, std::ios::binary);
    if (!file) throw std::runtime_error("Cannot open dataset: " + path);

    std::vector<float> h_data(num_points_ * dim_);
    file.read(reinterpret_cast<char*>(h_data.data()), h_data.size() * sizeof(float));
    CUDA_CHECK(cudaMemcpy(d_data_, h_data.data(), h_data.size() * sizeof(float), cudaMemcpyHostToDevice));
    log("Dataset loaded: " + std::to_string(num_points_) + " x " + std::to_string(dim_));
}

