void KNNWrapper::refineGraph(int k_refine, float threshold) {
    log("Refining graph: k_refine=" + std::to_string(k_refine) + ", threshold=" + std::to_string(threshold));
    mutualKNNRefineGPU(k_refine, threshold);
}

void KNNWrapper::mutualKNNRefineGPU(int k_refine, float threshold) {
