void KNNWrapper::generateReferenceData(int k_ref, const std::string& out_path) {
    log("Generating reference data with k=" + std::to_string(k_ref));
    // Вычисление точного KNN для всех точек (или подмножества)
    // Сохранение в бинарный формат: [N][k_ref][int] + [N][k_ref][float]
    std::ofstream file(out_path, std::ios::binary);
    if (!file) throw std::runtime_error("Cannot write reference: " + out_path);
    // Заглушка: запись нулей
    std::vector<int> idx(num_points_ * k_ref, 0);
    std::vector<float> dist(num_points_ * k_ref, 0.0f);
    file.write(reinterpret_cast<char*>(idx.data()), idx.size() * sizeof(int));
    file.write(reinterpret_cast<char*>(dist.data()), dist.size() * sizeof(float));
    log("Reference data saved.");
}

void KNNWrapper::evaluateGraph(const std::string& ref_path, float& recall, double& latency_ms) {
    log("Evaluating graph against reference...");
    std::ifstream file(ref_path, std::ios::binary);
    if (!file) throw std::runtime_error("Cannot open reference: " + ref_path);

    std::vector<int> ref_idx(num_points_ * k_);
    file.read(reinterpret_cast<char*>(ref_idx.data()), ref_idx.size() * sizeof(int));

    std::vector<int> h_graph_idx(num_points_ * k_);
    CUDA_CHECK(cudaMemcpy(h_graph_idx.data(), d_graph_indices_, h_graph_idx.size() * sizeof(int), cudaMemcpyDeviceToHost));

    int correct = 0;
    int total = num_points_ * k_;
    for (int i = 0; i < total; ++i) {
        if (h_graph_idx[i] == ref_idx[i]) correct++;
    }
    recall = static_cast<float>(correct) / total;
    latency_ms = 0.0; // Замеряется при query()
    log("Recall@k: " + std::to_string(recall));
}

QueryResult KNNWrapper::query(const float* queries, int num_queries, int k, bool verbose) {
    auto start = std::chrono::high_resolution_clock::now();

    float* d_queries = nullptr;
    int* d_indices = nullptr;
    float* d_distances = nullptr;

    CUDA_CHECK(cudaMalloc(&d_queries, num_queries * dim_ * sizeof(float)));
    CUDA_CHECK(cudaMalloc(&d_indices, num_queries * k * sizeof(int)));
    CUDA_CHECK(cudaMalloc(&d_distances, num_queries * k * sizeof(float)));

    CUDA_CHECK(cudaMemcpy(d_queries, queries, num_queries * dim_ * sizeof(float), cudaMemcpyHostToDevice));

    computeDistancesGPU(d_queries, num_queries, d_indices, d_distances);
    topKSelectionGPU(d_distances, num_queries, k, d_indices, d_distances);

    QueryResult res;
    res.indices.resize(num_queries * k);
    res.distances.resize(num_queries * k);

    CUDA_CHECK(cudaMemcpy(res.indices.data(), d_indices, res.indices.size() * sizeof(int), cudaMemcpyDeviceToHost));
    CUDA_CHECK(cudaMemcpy(res.distances.data(), d_distances, res.distances.size() * sizeof(float), cudaMemcpyDeviceToHost));

    auto end = std::chrono::high_resolution_clock::now();
    res.query_time_ms = std::chrono::duration<double, std::milli>(end - start).count();

    if (verbose) {
        std::cout << "[Query] Time: " << res.query_time_ms << " ms\n";
        std::cout << "[Query] First result indices: ";
        for (int i = 0; i < std::min(k, 5); ++i) std::cout << res.indices[i] << " ";
        std::cout << "\n";
    }

    cudaFree(d_queries);
    cudaFree(d_indices);
    cudaFree(d_distances);
    return res;
}

