void KNNWrapper::saveGraph(const std::string& path) const {
    std::ofstream file(path, std::ios::binary);
    if (!file) throw std::runtime_error("Cannot save graph: " + path);

    int header[3] = {num_points_, k_, dim_};
    file.write(reinterpret_cast<char*>(header), sizeof(header));

    std::vector<int> h_idx(num_points_ * k_);
    std::vector<float> h_dist(num_points_ * k_);
    CUDA_CHECK(cudaMemcpy(h_idx.data(), d_graph_indices_, h_idx.size() * sizeof(int), cudaMemcpyDeviceToHost));
    CUDA_CHECK(cudaMemcpy(h_dist.data(), d_graph_distances_, h_dist.size() * sizeof(float), cudaMemcpyDeviceToHost));

    file.write(reinterpret_cast<char*>(h_idx.data()), h_idx.size() * sizeof(int));
    file.write(reinterpret_cast<char*>(h_dist.data()), h_dist.size() * sizeof(float));
    log("Graph saved to " + path);
}

void KNNWrapper::loadGraph(const std::string& path) {
    std::ifstream file(path, std::ios::binary);
    if (!file) throw std::runtime_error("Cannot load graph: " + path);

    int header[3];
    file.read(reinterpret_cast<char*>(header), sizeof(header));
    num_points_ = header[0];
    k_ = header[1];
    dim_ = header[2];

    allocateDeviceMemory();

    std::vector<int> h_idx(num_points_ * k_);
    std::vector<float> h_dist(num_points_ * k_);
    file.read(reinterpret_cast<char*>(h_idx.data()), h_idx.size() * sizeof(int));
    file.read(reinterpret_cast<char*>(h_dist.data()), h_dist.size() * sizeof(float));

    CUDA_CHECK(cudaMemcpy(d_graph_indices_, h_idx.data(), h_idx.size() * sizeof(int), cudaMemcpyHostToDevice));
    CUDA_CHECK(cudaMemcpy(d_graph_distances_, h_dist.data(), h_dist.size() * sizeof(float), cudaMemcpyHostToDevice));
    log("Graph loaded from " + path);
}

void KNNWrapper::resetSubset(int new_size) {
    if (new_size <= 0 || new_size > num_points_) {
        throw std::invalid_argument("Invalid subset size");
    }
    num_points_ = new_size;
    allocateDeviceMemory(); // Перевыделение под новый размер
    log("Graph reset to subset size: " + std::to_string(new_size));
}
