const fs = require('fs');
const path = require('path');

// Пути
const ROOT = path.resolve(__dirname, '..');
const SRC_DIR = path.join(ROOT, 'src');
const DIST_DIR = path.join(ROOT, 'dist');
const PUBLIC_DIR = path.join(ROOT, 'public');

// Утилиты
const ensureDir = (dir) => {
  if (!fs.existsSync(dir)) fs.mkdirSync(dir, { recursive: true });
};

const cleanDir = (dir) => {
  if (fs.existsSync(dir)) fs.rmSync(dir, { recursive: true, force: true });
};

// 1. Очистка и подготовка директорий
function setupDirectories() {
  cleanDir(DIST_DIR);
  cleanDir(PUBLIC_DIR);
  ensureDir(DIST_DIR);
  ensureDir(PUBLIC_DIR);
  ['css', 'js', 'images', 'fonts'].forEach(sub => ensureDir(path.join(PUBLIC_DIR, sub)));
  console.log('📁 Директории подготовлены');
}

// 2. Генерация файлов парсеров
function generateParsers() {
  const parserDir = path.join(SRC_DIR, 'parsers');
  ensureDir(parserDir);

  const config = {
    className: 'JsonParser',
    methods: ['parse', 'validate', 'transform']
  };

  const code = `// ⚠️ Auto-generated parser. Do not edit manually.
export class ${config.className} {
  ${config.methods.map(m => `  ${m}(data) { /* implementation */ }`).join('\n')}
}
`;
  fs.writeFileSync(path.join(parserDir, 'jsonParser.js'), code, 'utf8');
  console.log('🔧 Парсеры сгенерированы');
}

// 3. Генерация шаблонов
function generateTemplates() {
  const tplDir = path.join(SRC_DIR, 'templates');
  ensureDir(tplDir);

  const data = { title: 'Web Project', body: '<main><h1>Welcome</h1></main>' };
  const html = `<!DOCTYPE html>
<html lang="ru">
<head>
  <meta charset="UTF-8">
  <title>${data.title}</title>
  <link rel="stylesheet" href="/css/style.css">
</head>
<body>
  ${data.body}
  <script src="/js/app.js"></script>
</body>
</html>`;

  fs.writeFileSync(path.join(tplDir, 'index.html'), html, 'utf8');
  console.log('📄 Шаблоны сгенерированы');
}

// 4. Сборка финальных файлов
function buildOutput() {
  // Копируем сгенерированные src → dist
  const copyRecursive = (src, dest) => {
    const stat = fs.statSync(src);
    if (stat.isDirectory()) {
      ensureDir(dest);
      fs.readdirSync(src).forEach(child => copyRecursive(path.join(src, child), path.join(dest, child)));
    } else {
      fs.copyFileSync(src, dest);
    }
  };
  copyRecursive(SRC_DIR, DIST_DIR);

  // Формируем публичные ассеты (в реальном проекте здесь будет Webpack/Vite/Sass)
  fs.writeFileSync(path.join(PUBLIC_DIR, 'js', 'app.js'), '// Compiled application bundle\nconsole.log("App initialized");', 'utf8');
  fs.writeFileSync(path.join(PUBLIC_DIR, 'css', 'style.css'), 'body { margin: 0; font-family: system-ui, sans-serif; }', 'utf8');

  console.log('📦 Финальные файлы собраны');
}

// Точка входа
function runBuild() {
  console.log('🚀 Запуск системы сборки...');
  try {
    setupDirectories();
    generateParsers();
    generateTemplates();
    buildOutput();
    console.log('✅ Сборка завершена успешно!');
  } catch (err) {
    console.error('❌ Ошибка сборки:', err.message);
    process.exit(1);
  }
}

runBuild();
```

