Ниже представлена полная, оптимизированная реализация симуляции Игры Жизни на CUDA C++, спроектированная для интеграции с много-GPU фреймворками (включая MAPS-Multi). Код включает ядро с разделяемой памятью, менеджер распределения нагрузки по GPU, механизм обмена граничными областями (halo exchange), регрессионное тестирование и сохранение изображений при ошибках.

### 📦 Полный исходный код (`gol_multigpu.cu`)

```cpp
#include <cuda_runtime.h>
#include <iostream>
#include <vector>
#include <fstream>
#include <cstring>
#include <string>
#include <algorithm>

// Макрос для проверки ошибок CUDA
#define CUDA_CHECK(call) \
    do { \
        cudaError_t err = call; \
        if (err != cudaSuccess) { \
            std::cerr << "CUDA Error: " << cudaGetErrorString(err) \
                      << " at " << __FILE__ << ":" << __LINE__ << std::endl; \
            exit(EXIT_FAILURE); \
        } \
    } while (0)

// Параметры блока (оптимально для современных GPU)
#define BLOCK_X 16
#define BLOCK_Y 16

// ============================================================================
// CUDA ЯДРО: Игра Жизни с оптимизацией через разделяемую память
// ============================================================================
__global__ void gameOfLifeKernel(const uint8_t* d_in, uint8_t* d_out, int width, int height) {
    int tx = threadIdx.x;
    int ty = threadIdx.y;
    int x = blockIdx.x * blockDim.x + tx;
    int y = blockIdx.y * blockDim.y + ty;

    // Разделяемая память с halo-областью (граница +1 с каждой стороны)
    __shared__ uint8_t tile[BLOCK_Y + 2][BLOCK_X + 2];

    // Загрузка центральной области
    if (x < width && y < height) {
        tile[ty + 1][tx + 1] = d_in[y * width + x];
    }

    // Загрузка halo-области (верх, низ, лево, право, углы)
    // Для много-GPU симуляции границы обычно заполняются хостом через halo-exchange.
    // Здесь реализованы тороидальные (wrap-around) границы для автономной работы.
    if (ty == 0) {
        int ny = (y == 0) ? height - 1 : y - 1;
        if (x < width) tile[0][tx + 1] = d_in[ny * width + x];
    }
    if (ty == BLOCK_Y - 1) {
        int ny = (y + 1) % height;
        if (x < width) tile[BLOCK_Y + 1][tx + 1] = d_in[ny * width + x];
    }
    if (tx == 0) {
        int nx = (x == 0) ? width - 1 : x - 1;
        if (y < height) tile[ty + 1][0] = d_in[y * width + nx];
    }
    if (tx == BLOCK_X - 1) {
        int nx = (x + 1) % width;
        if (y < height) tile[ty + 1][BLOCK_X + 1] = d_in[y * width + nx];
    }
    if (tx == 0 && ty == 0) {
        int nx = (x == 0) ? width - 1 : x - 1;
        int ny = (y == 0) ? height - 1 : y - 1;
        tile[0][0] = d_in[ny * width + nx];
    }
    if (tx == BLOCK_X - 1 && ty == 0) {
        int nx = (x + 1) % width;
        int ny = (y == 0) ? height - 1 : y - 1;
        tile[0][BLOCK_X + 1] = d_in[ny * width + nx];
    }
    if (tx == 0 && ty == BLOCK_Y - 1) {
        int nx = (x == 0) ? width - 1 : x - 1;
        int ny = (y + 1) % height;
        tile[BLOCK_Y + 1][0] = d_in[ny * width + nx];
    }
    if (tx == BLOCK_X - 1 && ty == BLOCK_Y - 1) {
        int nx = (x + 1) % width;
        int ny = (y + 1) % height;
        tile[BLOCK_Y + 1][BLOCK_X + 1] = d_in[ny * width + nx];
    }

    __syncthreads();

    if (x < width && y < height) {
        int neighbors = 0;
        #pragma unroll
        for (int dy = -1; dy <= 1; ++dy) {
            #pragma unroll
            for (int dx = -1; dx <= 1; ++dx) {
                if (dx == 0 && dy == 0) continue;
                neighbors += tile[ty + 1 + dy][tx + 1 + dx];
            }
        }

        uint8_t current = tile[ty + 1][tx + 1];
        // Правила Conway's Game of Life
        d_out[y * width + x] = (current == 1) ? 
            ((neighbors == 2 || neighbors == 3) ? 1 : 0) : 
            ((neighbors == 3) ? 1 : 0);
    }
}

// ============================================================================
// Вспомогательные функции: Регрессионное тестирование и сохранение изображений
// ============================================================================
void saveGridAsPPM(const uint8_t* grid, int width, int height, const std::string& filename) {
    std::ofstream file(filename, std::ios::binary);
    if (!file.is_open()) {
        std::cerr << "Ошибка: не удалось открыть файл " << filename << " для записи\n";
        return;
    }
    file << "P6\n" << width << " " << height << "\n255\n";
    for (int i = 0; i < width * height; ++i) {
        uint8_t val = grid[i] ? 255 : 0;
        file.write(reinterpret_cast<char*>(&val), 1);
        file.write(reinterpret_cast<char*>(&val), 1);
        file.write(reinterpret_cast<char*>(&val), 1);
    }
    file.close();
    std::cout << "Изображение сохранено: " << filename << "\n";
}

bool runRegressionTest(const uint8_t* h_result, const uint8_t* h_reference, 
                       int width, int height, const std::string& fail_img_path) {
    size_t total = width * height;
    for (size_t i = 0; i < total; ++i) {
        if (h_result[i] != h_reference[i]) {
            std::cerr << "❌ Регрессионный тест не пройден. Расхождение на индексе " << i << "\n";
            saveGridAsPPM(h_result, width, height, fail_img_path);
            return false;
        }
    }
    std::cout << "✅ Регрессионный тест пройден успешно.\n";
    return true;
}

// ============================================================================
// Менеджер много-GPU выполнения (адаптируемый под MAPS-Multi)
// ============================================================================
class GoLMultiGPUManager {
public:
    GoLMultiGPUManager(int width, int height, int num_gpus) 
        : width_(width), height_(height), num_gpus_(num_gpus) {

        if (num_gpus_ <= 0) num_gpus_ = 1;
        int device_count;
        CUDA_CHECK(cudaGetDeviceCount(&device_count));
        if (num_gpus_ > device_count) {
            std::cerr << "Предупреждение: запрошено " << num_gpus_ 
                      << " GPU, доступно " << device_count << ". Используем " << device_count << ".\n";
            num_gpus_ = device_count;
        }

        // Распределяем строки между GPU
        rows_per_gpu_ = (height_ + num_gpus_ - 1) / num_gpus_;
        local_height_ = rows_per_gpu_ + 2; // +2 для halo-областей

        d_in_.resize(num_gpus_);
        d_out_.resize(num_gpus_);
        streams_.resize(num_gpus_);

        for (int i = 0; i < num_gpus_; ++i) {
            CUDA_CHECK(cudaSetDevice(i));
            CUDA_CHECK(cudaStreamCreate(&streams_[i]));
            size_t bytes = width_ * local_height_ * sizeof(uint8_t);
            CUDA_CHECK(cudaMallocAsync(&d_in_[i], bytes, streams_[i]));
            CUDA_CHECK(cudaMallocAsync(&d_out_[i], bytes, streams_[i]));
        }
    }

    ~GoLMultiGPUManager() {
        for (int i = 0; i < num_gpus_; ++i) {
            CUDA_CHECK(cudaSetDevice(i));
            CUDA_CHECK(cudaFreeAsync(d_in_[i], streams_[i]));
            CUDA_CHECK(cudaFreeAsync(d_out_[i], streams_[i]));
            CUDA_CHECK(cudaStreamDestroy(streams_[i]));
        }
    }

    void step(const std::vector<uint8_t>& h_grid) {
        // 1. Копируем данные на каждый GPU (с учетом halo)
        for (int i = 0; i < num_gpus_; ++i) {
            CUDA_CHECK(cudaSetDevice(i));
            int row_start = i * rows_per_gpu_;
            int row_end = std::min(row_start + rows_per_gpu_, height_);
            int local_rows = row_end - row_start;

            // Копируем основную область
            CUDA_CHECK(cudaMemcpy2DAsync(
                d_in_[i], width_ * sizeof(uint8_t),
                h_grid.data() + row_start * width_, width_ * sizeof(uint8_t),
                width_ * sizeof(uint8_t), local_rows,
                cudaMemcpyHostToDevice, streams_[i]));

            // Заполняем halo (упрощенно: копируем соседние строки или используем wrap)
            // В реальном MAPS-Multi здесь будет peer-to-peer или MPI обмен
            fillHalo(i, row_start, row_end, h_grid);
        }

        // 2. Запускаем ядра асинхронно
        dim3 block(BLOCK_X, BLOCK_Y);
        dim3 grid((width_ + BLOCK_X - 1) / BLOCK_X, (rows_per_gpu_ + BLOCK_Y - 1) / BLOCK_Y);

        for (int i = 0; i < num_gpus_; ++i) {
            CUDA_CHECK(cudaSetDevice(i));
            gameOfLifeKernel<<<grid, block, 0, streams_[i]>>>(d_in_[i], d_out_[i], width_, rows_per_gpu_);
        }

        // 3. Синхронизация и сбор результатов
        std::vector<uint8_t> h_next(height_ * width_, 0);
        for (int i = 0; i < num_gpus_; ++i) {
            CUDA_CHECK(cudaSetDevice(i));
            int row_start = i * rows_per_gpu_;
            int row_end = std::min(row_start + rows_per_gpu_, height_);
            int local_rows = row_end - row_start;

            CUDA_CHECK(cudaMemcpy2DAsync(
                h_next.data() + row_start * width_, width_ * sizeof(uint8_t),
                d_out_[i], width_ * sizeof(uint8_t),
                width_ * sizeof(uint8_t), local_rows,
                cudaMemcpyDeviceToHost, streams_[i]));
        }

        for (int i = 0; i < num_gpus_; ++i) {
            CUDA_CHECK(cudaSetDevice(i));
            CUDA_CHECK(cudaStreamSynchronize(streams_[i]));
        }

        // Обновляем входные данные для следующего шага
        const_cast<std::vector<uint8_t>&>(h_grid) = h_next;
    }

private:
    int width_, height_, num_gpus_;
    int rows_per_gpu_, local_height_;
    std::vector<uint8_t*> d_in_, d_out_;
    std::vector<cudaStream_t> streams_;

    void fillHalo(int gpu_id, int row_start, int row_end, const std::vector<uint8_t>& h_grid) {
        // Упрощенная реализация halo для демонстрации.
        // В production-коде MAPS-Multi использует cudaIpcGetMemHandle / cudaMemcpyPeer / MPI.
        CUDA_CHECK(cudaSetDevice(gpu_id));

        // Верхняя граница
        if (row_start > 0) {
            int src_row = row_start - 1;
            CUDA_CHECK(cudaMemcpy2DAsync(
                d_in_[gpu_id] + width_, width_ * sizeof(uint8_t),
                h_grid.data() + src_row * width_, width_ * sizeof(uint8_t),
                width_ * sizeof(uint8_t), 1,
                cudaMemcpyHostToDevice, streams_[gpu_id]));
        } else {
            // Wrap-around или нули
            int src_row = height_ - 1;
            CUDA_CHECK(cudaMemcpy2DAsync(
                d_in_[gpu_id], width_ * sizeof(uint8_t),
                h_grid.data() + src_row * width_, width_ * sizeof(uint8_t),
                width_ * sizeof(uint8_t), 1,
                cudaMemcpyHostToDevice, streams_[gpu_id]));
        }

        // Нижняя граница
        if (row_end < height_) {
            int src_row = row_end;
            CUDA_CHECK(cudaMemcpy2DAsync(
                d_in_[gpu_id] + (local_height_ - 1) * width_, width_ * sizeof(uint8_t),
                h_grid.data() + src_row * width_, width_ * sizeof(uint8_t),
                width_ * sizeof(uint8_t), 1,
                cudaMemcpyHostToDevice, streams_[gpu_id]));
        } else {
            int src_row = 0;
            CUDA_CHECK(cudaMemcpy2DAsync(
                d_in_[gpu_id] + (local_height_ - 1) * width_, width_ * sizeof(uint8_t),
                h_grid.data() + src_row * width_, width_ * sizeof(uint8_t),
                width_ * sizeof(uint8_t), 1,
                cudaMemcpyHostToDevice, streams_[gpu_id]));
        }
    }
};

// ============================================================================
// Точка входа
// ============================================================================
int main() {
    const int WIDTH = 1024;
    const int HEIGHT = 1024;
    const int STEPS = 100;
    const int NUM_GPUS = 2; // Измените под вашу систему

    // Инициализация сетки (случайная)
    std::vector<uint8_t> grid(WIDTH * HEIGHT);
    for (auto& cell : grid) cell = (rand() % 4 == 0) ? 1 : 0;

    // Эталонная копия для регрессионного теста
    std::vector<uint8_t> reference_grid = grid;

    // CPU-реализация для генерации эталона (упрощенная)
    auto cpuStep = [](std::vector<uint8_t>& g, int w, int h) {
        std::vector<uint8_t> next = g;
        for (int y = 0; y < h; ++y) {
            for (int x = 0; x < w; ++x) {
                int neighbors = 0;
                for (int dy = -1; dy <= 1; ++dy) {
                    for (int dx = -1; dx <= 1; ++dx) {
                        if (dx == 0 && dy == 0) continue;
                        int nx = (x + dx + w) % w;
                        int ny = (y + dy + h) % h;
                        neighbors += g[ny * w + nx];
                    }
                }
                int idx = y * w + x;
                next[idx] = (g[idx] == 1) ? ((neighbors == 2 || neighbors == 3) ? 1 : 0) : ((neighbors == 3) ? 1 : 0);
            }
        }
        g = next;
    };

    // Генерируем эталон на CPU
    for (int i = 0; i < STEPS; ++i) cpuStep(reference_grid, WIDTH, HEIGHT);

    // Запуск на GPU
    GoLMultiGPUManager manager(WIDTH, HEIGHT, NUM_GPUS);
    for (int i = 0; i < STEPS; ++i) {
        manager.step(grid);
    }

    // Регрессионный тест
    bool passed = runRegressionTest(grid.data(), reference_grid.data(), WIDTH, HEIGHT, "gol_fail.ppm");
    if (!passed) {
        std::cerr << "Тест не пройден. Проверьте gol_fail.ppm\n";
        return EXIT_FAILURE;
    }

    std::cout << "Симуляция завершена успешно.\n";
    return EXIT_SUCCESS;
}
```

### 🔍 Ключевые оптимизации и архитектурные решения

| Компонент | Оптимизация | Обоснование |
|-----------|-------------|-------------|
| **Разделяемая память** | `__shared__ uint8_t tile[BLOCK_Y+2][BLOCK_X+2]` | Снижает количество обращений к глобальной памяти с 9 до ~1 на клетку. Устраняет узкое место пропускной способности. |
| **Halo-область** | Явная загрузка границ + `__syncthreads()` | Позволяет каждому потоку читать соседей из быстрой shared memory без атомарных операций или повторных глобальных чтений. |
| **Много-GPU** | Горизонтальное разбиение + асинхронные потоки | Каждый GPU обрабатывает свою полосу строк. `cudaStream_t` позволяет перекрывать вычисления и передачу данных. |
| **Границы** | Тороидальные (wrap-around) | Стандарт для бенчмарков GoL. В production-коде MAPS-Multi заменяет это на `cudaMemcpyPeer` или MPI-обмен между узлами. |
| **Регрессия** | Побайтовое сравнение + PPM-дамп | Формат PPM не требует внешних библиотек. Сохраняется только при расхождении, что экономит I/O. |

### 🔌 Интеграция с MAPS-Multi

Фреймворк MAPS-Multi обычно предоставляет абстракции для:
1. **Устройства**: `maps::DeviceManager::getDevices()`
2. **Памяти**: `maps::MemoryPool::allocate()`
3. **Синхронизации**: `maps::Barrier::wait()`
4. **Обмена границами**: `maps::HaloExchange::pushPull()`

Для адаптации кода:
- Замените `cudaSetDevice` на вызовы менеджера устройств MAPS.
- Замените ручное `cudaMemcpy2DAsync` на `maps::HaloExchange` (обычно использует NVLink/PCIe peer-to-peer).
- Оберните запуск ядра в `maps::KernelLauncher::launch()`.
- Регрессионный тест можно вынести в `maps::Validator::compare()`.

### 🛠 Компиляция и запуск

```bash
# Компиляция (требуется CUDA 11.0+)
nvcc -O3 -arch=sm_70 -std=c++17 gol_multigpu.cu -o gol_multigpu

# Запуск
./gol_multigpu
```

### 📌 Примечания для production
1. **Peer-to-Peer доступ**: Включите `cudaDeviceEnablePeerAccess()` между GPU для ускорения halo-обмена.
2. **Динамическое разбиение**: Для неоднородных GPU используйте `cudaMemGetInfo()` для балансировки нагрузки.
3. **Double buffering**: В реальном коде используйте два буфера на GPU, чтобы избежать синхронизации между шагами.
4. **Векторизация**: Для сеток >4K используйте `uint4` или `uchar4` для коалесцированных чтений.

